import numpy as np

def classify_quadratic_form(matrix):
 """Classify quadratic form using eigenvalue test"""
 eigenvalues = np.linalg.eigvalsh(matrix)

 # Check definiteness
 if all(eigenvalues > 0):
 return "Positive Definite"
 elif all(eigenvalues < 0):
 return "Negative Definite"
 elif all(eigenvalues >= 0):
 return "Positive Semidefinite"
 elif all(eigenvalues <= 0):
 return "Negative Semidefinite"
 else:
 return "Indefinite"

# Example
A = np.array([[2, 1], [1, 2]])
print(classify_quadratic_form(A)) # Output: Positive Definite
